CREATE TABLE `biz_achievement` (
  `ach_id` bigint NOT NULL AUTO_INCREMENT COMMENT '成果ID',
  `category` int NOT NULL COMMENT '类别',
  `level` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '级别',
  `ach_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '成果名称',
  `department` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '组织部门 如：教育部办公厅等，注意不同于校内部门',
  `got_time` datetime NOT NULL COMMENT '颁发时间',
  `dept_id` bigint NOT NULL COMMENT '部门ID',
  `file_id` bigint DEFAULT NULL COMMENT '佐证材料文件ID',
  `comment` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '备注',
  `is_competition` tinyint(1) DEFAULT '0' COMMENT '是否竞赛 0:不是竞赛 1:是竞赛',
  `te_deng_jiang` int DEFAULT '0' COMMENT '特等奖数量',
  `yi_deng_jiang` int DEFAULT '0' COMMENT '一等奖数量',
  `er_deng_jiang` int DEFAULT '0' COMMENT '二等奖数量',
  `san_deng_jiang` int DEFAULT '0' COMMENT '三等奖数量',
  `jin_jiang` int DEFAULT '0' COMMENT '金奖数量',
  `yin_jiang` int DEFAULT '0' COMMENT '银奖数量',
  `tong_jiang` int DEFAULT '0' COMMENT '铜奖数量',
  `you_sheng_jiang` int DEFAULT '0' COMMENT '优胜奖数量',
  `bud_deng_deng_ci` int DEFAULT '0' COMMENT '不定等次数量',
  `create_by` bigint DEFAULT NULL COMMENT '创建人ID',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '0:存在 1:删除',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`ach_id`),
  KEY `fk_ach_user` (`create_by`),
  CONSTRAINT `fk_ach_user` FOREIGN KEY (`create_by`) REFERENCES `sys_user` (`user_id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='标志性成果表';
