--
-- Table structure for table `biz_level4_task`
--

DROP TABLE IF EXISTS `biz_level4_task`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `biz_level4_task` (
  `task_id` bigint NOT NULL AUTO_INCREMENT COMMENT '任务ID',
  `parent_id` bigint DEFAULT '0' COMMENT '父任务节点ID',
  `phase` int DEFAULT NULL COMMENT '所属年份',
  `task_name` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '任务名称',
  `leader_id` bigint DEFAULT NULL COMMENT '任务负责人ID',
  `dept_id` bigint NOT NULL COMMENT '归口部门ID',
  `data_type` char(1) COLLATE utf8mb4_unicode_ci DEFAULT '1' COMMENT '数据类型 0:对指标没有影响 1:数值(累加) 2:百分比(取大)',
  `target_value` decimal(20,4) DEFAULT '0.0000' COMMENT '目标值',
  `current_value` decimal(20,4) DEFAULT '0.0000' COMMENT '当前完成值(缓存统计)',
  `progress` int DEFAULT '0' COMMENT '任务进度(冗余)',
  `status` char(1) COLLATE utf8mb4_unicode_ci DEFAULT '0' COMMENT '0:未开始 1:进行中 2:审核中 3:已完成',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '0:存在 1:删除',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`task_id`),
  KEY `idx_parent` (`parent_id`),
  KEY `idx_phase` (`phase`),
  KEY `fk_level4_task_dept` (`dept_id`),
  KEY `fk_level4_task_leader` (`leader_id`),
  CONSTRAINT `fk_level4_task_dept` FOREIGN KEY (`dept_id`) REFERENCES `sys_dept` (`dept_id`) ON DELETE RESTRICT,
  CONSTRAINT `fk_level4_task_leader` FOREIGN KEY (`leader_id`) REFERENCES `sys_user` (`user_id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=746 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='四级任务表';
/*!40101 SET character_set_client = @saved_cs_client */;

