--
-- Table structure for table `biz_material_submission`
--

DROP TABLE IF EXISTS `biz_material_submission`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `biz_material_submission` (
  `sub_id` bigint NOT NULL AUTO_INCREMENT COMMENT '提交ID',
  `task_id` bigint NOT NULL COMMENT '任务ID',
  `file_id` bigint NOT NULL COMMENT '文件ID',
  `reported_value` decimal(20,4) DEFAULT '0.0000' COMMENT '本次填报完成值',
  `data_type` char(1) COLLATE utf8mb4_unicode_ci DEFAULT '1' COMMENT '数据类型 0:对指标没有影响 1:数值(累加) 2:百分比(取大)',
  `submit_by` bigint NOT NULL COMMENT '提交人ID',
  `submit_dept_id` bigint NOT NULL COMMENT '提交人部门ID',
  `manage_dept_id` bigint NOT NULL COMMENT '归口部门ID',
  `submit_time` datetime DEFAULT CURRENT_TIMESTAMP,
  `file_suffix` varchar(10) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '后缀',
  `flow_status` int DEFAULT '0' COMMENT '流程状态',
  `current_handler_id` bigint DEFAULT NULL COMMENT '当前处理人ID',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '0:存在 1:删除',
  PRIMARY KEY (`sub_id`),
  KEY `fk_sub_file` (`file_id`),
  KEY `fk_sub_user` (`submit_by`),
  KEY `fk_sub_task` (`task_id`),
  KEY `fk_sub_handler` (`current_handler_id`),
  KEY `fk_sub_dept1` (`submit_dept_id`),
  KEY `fk_sub_dept2` (`manage_dept_id`),
  CONSTRAINT `fk_sub_dept1` FOREIGN KEY (`submit_dept_id`) REFERENCES `sys_dept` (`dept_id`) ON DELETE RESTRICT,
  CONSTRAINT `fk_sub_dept2` FOREIGN KEY (`manage_dept_id`) REFERENCES `sys_dept` (`dept_id`) ON DELETE RESTRICT,
  CONSTRAINT `fk_sub_file` FOREIGN KEY (`file_id`) REFERENCES `sys_file` (`file_id`) ON DELETE RESTRICT,
  CONSTRAINT `fk_sub_handler` FOREIGN KEY (`current_handler_id`) REFERENCES `sys_user` (`user_id`) ON DELETE SET NULL,
  CONSTRAINT `fk_sub_task` FOREIGN KEY (`task_id`) REFERENCES `biz_task` (`task_id`) ON DELETE CASCADE,
  CONSTRAINT `fk_sub_user` FOREIGN KEY (`submit_by`) REFERENCES `sys_user` (`user_id`) ON DELETE RESTRICT,
  CONSTRAINT `chk_file_format` CHECK ((`file_suffix` in (_utf8mb4'pdf',_utf8mb4'doc',_utf8mb4'docx')))
) ENGINE=InnoDB AUTO_INCREMENT=147 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='审批流转与填报表';
/*!40101 SET character_set_client = @saved_cs_client */;

