--
-- Table structure for table `biz_audit_snapshot`
--

DROP TABLE IF EXISTS `biz_audit_snapshot`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `biz_audit_snapshot` (
  `snapshot_id` bigint NOT NULL AUTO_INCREMENT COMMENT '快照ID',
  `sub_id` bigint NOT NULL COMMENT '提交ID',
  `target_type` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '对象类型 TASK/LEVEL4_TASK',
  `target_id` bigint NOT NULL COMMENT '任务ID或四级任务ID',
  `previous_value` decimal(20,4) DEFAULT '0.0000' COMMENT '提交前完成值',
  `previous_status` char(1) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '提交前状态',
  `previous_comment` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '提交前任务备注',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`snapshot_id`),
  UNIQUE KEY `uk_audit_snapshot_target` (`sub_id`,`target_type`,`target_id`),
  KEY `idx_audit_snapshot_sub` (`sub_id`),
  CONSTRAINT `fk_snapshot_submission` FOREIGN KEY (`sub_id`) REFERENCES `biz_material_submission` (`sub_id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='审批提交前状态快照表';
/*!40101 SET character_set_client = @saved_cs_client */;

