--
-- Table structure for table `biz_performance`
--

DROP TABLE IF EXISTS `biz_performance`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `biz_performance` (
  `perf_id` bigint NOT NULL AUTO_INCREMENT COMMENT '指标ID',
  `project_id` bigint NOT NULL,
  `parent_id` bigint DEFAULT '0',
  `ancestors` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT '',
  `perf_code` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '编码',
  `perf_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '名称',
  `target_value` decimal(20,4) DEFAULT '0.0000' COMMENT '总目标值',
  `current_value` decimal(20,4) DEFAULT '0.0000' COMMENT '当前完成值(计算得出)',
  `data_type` char(1) COLLATE utf8mb4_unicode_ci DEFAULT '1' COMMENT '数据类型 0:对指标没有影响 1:数值(累加) 2:百分比(取大)',
  `dept_id` bigint NOT NULL COMMENT '归口部门ID',
  `principal_id` bigint NOT NULL COMMENT '归口负责人ID',
  `auditor_id` bigint NOT NULL COMMENT '专业群审核人ID',
  `leader_id` bigint DEFAULT NULL COMMENT '任务负责人ID',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '0:存在 1:删除',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`perf_id`),
  KEY `fk_perf_dept` (`dept_id`),
  KEY `fk_perf_principal` (`principal_id`),
  CONSTRAINT `fk_perf_dept` FOREIGN KEY (`dept_id`) REFERENCES `sys_dept` (`dept_id`) ON DELETE RESTRICT,
  CONSTRAINT `fk_perf_principal` FOREIGN KEY (`principal_id`) REFERENCES `sys_user` (`user_id`) ON DELETE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=165 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='绩效指标库';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `biz_performance`
--

