DROP TABLE IF EXISTS `biz_performance_year`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `biz_performance_year` (
  `year_id` bigint NOT NULL AUTO_INCREMENT,
  `perf_id` bigint NOT NULL COMMENT '指标ID',
  `year` int NOT NULL,
  `target_value` decimal(20,4) DEFAULT '0.0000',
  `actual_value` decimal(20,4) DEFAULT '0.0000' COMMENT '年度实际完成',
  `data_type` char(1) COLLATE utf8mb4_unicode_ci DEFAULT '1' COMMENT '数据类型 0:对指标没有影响 1:数值(累加) 2:百分比(取大)',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '0:存在 1:删除',
  PRIMARY KEY (`year_id`),
  KEY `fk_year_perf` (`perf_id`),
  CONSTRAINT `fk_year_perf` FOREIGN KEY (`perf_id`) REFERENCES `biz_performance` (`perf_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=636 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='绩效年度表';
/*!40101 SET character_set_client = @saved_cs_client */;

