DROP TABLE IF EXISTS `biz_project`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `biz_project` (
  `project_id` bigint NOT NULL AUTO_INCREMENT COMMENT '项目ID',
  `project_name` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '项目名称',
  `project_code` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '项目编码',
  `leader_id` bigint DEFAULT NULL COMMENT '项目负责人ID',
  `start_date` date DEFAULT NULL,
  `end_date` date DEFAULT NULL,
  `status` char(1) COLLATE utf8mb4_unicode_ci DEFAULT '1' COMMENT '0:未开始 1:进行中 2:已完成 3:暂停 4:逾期',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '0:存在 1:删除',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`project_id`),
  KEY `fk_project_leader` (`leader_id`),
  CONSTRAINT `fk_project_leader` FOREIGN KEY (`leader_id`) REFERENCES `sys_user` (`user_id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='项目信息表';
