--
-- Table structure for table `biz_task`
--

DROP TABLE IF EXISTS `biz_task`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `biz_task` (
  `task_id` bigint NOT NULL AUTO_INCREMENT COMMENT '任务ID',
  `project_id` bigint NOT NULL COMMENT '项目ID',
  `parent_id` bigint DEFAULT '0' COMMENT '父任务节点ID',
  `ancestors` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '祖先',
  `phase` int DEFAULT NULL COMMENT '所属年份',
  `task_code` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '任务编号',
  `task_name` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '任务名称',
  `level` int DEFAULT '1' COMMENT '任务层级',
  `comment` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '任务情况描述',
  `leader_id` bigint DEFAULT NULL COMMENT '任务负责人ID',
  `auditor_id` bigint DEFAULT NULL COMMENT '审核人ID',
  `principal_id` bigint NOT NULL COMMENT '归口负责人ID',
  `dept_id` bigint NOT NULL COMMENT '归口部门ID',
  `exp_target` text COLLATE utf8mb4_unicode_ci COMMENT '预期达成情况',
  `exp_level` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '预期成果级别（国/省/市）',
  `exp_effect` text COLLATE utf8mb4_unicode_ci COMMENT '预期效果',
  `exp_material_desc` text COLLATE utf8mb4_unicode_ci COMMENT '预期过程（佐证）材料清单(文本描述)',
  `data_type` char(1) COLLATE utf8mb4_unicode_ci DEFAULT '1' COMMENT '数据类型 0:对指标没有影响 1:数值(累加) 2:百分比(取大)',
  `target_value` decimal(20,4) DEFAULT '0.0000' COMMENT '目标值',
  `current_value` decimal(20,4) DEFAULT '0.0000' COMMENT '当前完成值(缓存统计)',
  `weight` decimal(5,2) DEFAULT '1.00' COMMENT '权重(冗余)',
  `progress` int DEFAULT '0' COMMENT '任务进度(冗余)',
  `status` char(1) COLLATE utf8mb4_unicode_ci DEFAULT '0' COMMENT '0:未开始 1:进行中 2:审核中 3:已完成',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '0:存在 1:删除',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`task_id`),
  KEY `idx_project` (`project_id`),
  KEY `fk_task_dept` (`dept_id`),
  KEY `fk_task_principal` (`principal_id`),
  KEY `fk_task_leader` (`leader_id`),
  CONSTRAINT `fk_task_dept` FOREIGN KEY (`dept_id`) REFERENCES `sys_dept` (`dept_id`) ON DELETE RESTRICT,
  CONSTRAINT `fk_task_leader` FOREIGN KEY (`leader_id`) REFERENCES `sys_user` (`user_id`) ON DELETE SET NULL,
  CONSTRAINT `fk_task_principal` FOREIGN KEY (`principal_id`) REFERENCES `sys_user` (`user_id`) ON DELETE RESTRICT,
  CONSTRAINT `fk_task_project` FOREIGN KEY (`project_id`) REFERENCES `biz_project` (`project_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=636 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='任务分解表';
/*!40101 SET character_set_client = @saved_cs_client */;

