DROP TABLE IF EXISTS `biz_trend_data`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `biz_trend_data` (
  `data_id` bigint NOT NULL AUTO_INCREMENT COMMENT '数据ID',
  `year` int NOT NULL COMMENT '所属年份',
  `month` int NOT NULL COMMENT '所属月份',
  `day` int NOT NULL COMMENT '所属日',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '记录时间',
  `total_tasks` int DEFAULT '0' COMMENT '当年总任务数',
  `completion_count` int DEFAULT '0' COMMENT '完成数量',
  `completion_rate` decimal(5,2) DEFAULT '0.00' COMMENT '完成率(%)',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '0:存在 1:删除',
  PRIMARY KEY (`data_id`),
  KEY `idx_year_month` (`year`,`month`),
  KEY `idx_create_time` (`create_time`)
) ENGINE=InnoDB AUTO_INCREMENT=30 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='发展趋势数据表';
/*!40101 SET character_set_client = @saved_cs_client */;

