--
-- Table structure for table `sys_notice`
--

DROP TABLE IF EXISTS `sys_notice`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sys_notice` (
  `notice_id` bigint NOT NULL AUTO_INCREMENT COMMENT '通知ID',
  `from_user_id` bigint DEFAULT NULL COMMENT '发起人ID',
  `to_user_id` bigint NOT NULL COMMENT '接收人ID',
  `type` char(1) COLLATE utf8mb4_unicode_ci DEFAULT '1' COMMENT '类型',
  `trigger_event` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'SYSTEM' COMMENT '触发事件',
  `title` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '标题',
  `content` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '内容',
  `source_type` char(1) COLLATE utf8mb4_unicode_ci NOT NULL,
  `source_id` bigint DEFAULT NULL COMMENT '关联业务ID',
  `is_read` char(1) COLLATE utf8mb4_unicode_ci DEFAULT '0' COMMENT '阅读状态 0:未读 1:已读',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '0:存在 1:删除',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`notice_id`),
  KEY `idx_user_read` (`from_user_id`,`to_user_id`,`is_read`),
  KEY `fk_sup_to` (`to_user_id`),
  CONSTRAINT `fk_sup_from` FOREIGN KEY (`from_user_id`) REFERENCES `sys_user` (`user_id`) ON DELETE SET NULL,
  CONSTRAINT `fk_sup_to` FOREIGN KEY (`to_user_id`) REFERENCES `sys_user` (`user_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=235 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='系统通知表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `sys_notice`
--

